CREATE TABLE industries
(
	id serial,
	parent_id integer DEFAULT NULL,
	naics_code integer NOT NULL,
	naics_code_upper integer DEFAULT NULL,
	name character varying DEFAULT NULL,
	CONSTRAINT pk_industries PRIMARY KEY (id)
);
CREATE INDEX i_industries_name ON industries (name);
CREATE INDEX i_industries_parent_id ON industries (parent_id);
CREATE INDEX i_industries_naics_code ON industries (naics_code);
CREATE INDEX i_industries_naics_codes_range ON industries (naics_code, naics_code_upper);
